def determine_FMAD_hyperparameters(dataset_name_raw):
    dataset_name = dataset_name_raw.lower()
    if "census" in dataset_name:
        epoch_size = 5
        batch_size = 1024
        learning_rate = 0.005

elif "hepatitis" in dataset_name:
    epoch_size = 1
    batch_size = 512
    learning_rate = 0.005

return {
    "epochs": epoch_size,
    "learning_rate": learning_rate,
    "batch_size": batch_size
        }
